 * This test verifies that lambda bodies in chained calls have correct indentation.
 */
internal class IndentationRuleChainedCallTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a function with runCatching chained with getOrNull and let with lambda`() {
        val code =
            """
            private fun test(): Boolean? =
                runCatching { true }
                    .getOrNull()?.let { result ->
                        !result
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function with chained calls mixing dot and safe access with lambda on multiple lines`() {
        val code =
            """
            fun process(): String? =
                someValue
                    .transform()
                    ?.let { value ->
                        value.toString()
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a property with chained safe access and dot qualified expressions`() {
        val code =
            """
            val result =
                foo?.bar()
                    .baz()
                    ?.let { item ->
                        item.process()
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given deeply nested chained calls with mixed safe access and dot notation`() {
        val code =
            """
            val computed =
                data?.field
                    .method1()
                    ?.method2()
                    .method3()?.let { value ->
                        value * 2
                    }?.let { doubled ->
                        doubled + 1
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
